import React, { useState, useRef, useLayoutEffect } from 'react';
import { Link } from 'react-router-dom';
import { Product } from '../types/index';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faFacebook, faInstagram, faYoutube, faBlogger, faTwitter, faTelegram, IconDefinition } from '@fortawesome/free-brands-svg-icons';
import { faChevronLeft, faChevronRight, faHeart as faSolidHeart, faHeart as faRegularHeart, faStar as faSolidStar, faStarHalfAlt, faStar as faRegularStar } from '@fortawesome/free-solid-svg-icons';

const categoryIcon: Record<string, { icon: IconDefinition; color: string }> = {
  'ĒÄśņØ┤ņŖżļČü': { icon: faFacebook, color: 'text-blue-600' },
  'ņØĖņŖżĒāĆĻĘĖļ×©': { icon: faInstagram, color: 'text-pink-500' },
  'ņ£ĀĒŖ£ļĖī': { icon: faYoutube, color: 'text-red-600' },
  'ļĖöļĪ£ĻĘĖ': { icon: faBlogger, color: 'text-orange-500' },
  'ĒŖĖņ£äĒä░': { icon: faTwitter, color: 'text-sky-400' },
  'ĒģöļĀłĻĘĖļ×©': { icon: faTelegram, color: 'text-blue-400' },
  'ĻĖ░ĒāĆ': { icon: faBlogger, color: 'text-gray-400' },
};

const getSlidesToShow = () => {
  if (window.innerWidth < 640) return 1;
  if (window.innerWidth < 1024) return 2;
  return 4;
};

const Home: React.FC = () => {
  const [recentProducts, setRecentProducts] = useState<Product[]>([]);
  const [selectedCategory, setSelectedCategory] = useState<string>('ņĀäņ▓┤');
  const [slideIndex, setSlideIndex] = useState(0);
  const [favorites, setFavorites] = useState<number[]>([]);
  const [slidesToShow, setSlidesToShow] = useState(getSlidesToShow());

  // ņŖ¼ļØ╝ņØ┤ļō£ ĒŖĖļ×Ö ref ļ░Å ņ╗©ĒģīņØ┤ļäł width
  const trackRef = useRef<HTMLDivElement>(null);
  const [containerWidth, setContainerWidth] = useState(0);

  const categories: string[] = ['ņĀäņ▓┤', 'ĒÄśņØ┤ņŖżļČü', 'ņØĖņŖżĒāĆĻĘĖļ×©', 'ņ£ĀĒŖ£ļĖī', 'ļĖöļĪ£ĻĘĖ', 'ĒŖĖņ£äĒä░', 'ĒģöļĀłĻĘĖļ×©', 'ĻĖ░ĒāĆ'];

  // Mock data for popular products (clickCount ņČöĻ░Ć)
  const popularProducts: Product[] = [
    {
      id: 1,
      name: 'ņ£ĀĒŖ£ļĖī ļ¦łņ╝ĆĒīģ ĒÖ£ņä▒ĒÖö',
      description: 'ņ£ĀĒŖ£ļĖī ĻĄ¼ļÅģņ×É,ņĪ░ĒÜīņłś,ņóŗņĢäņÜö,ņłśņØĄņ░ĮņČ£,ņŖżĒŖĖļ”¼ļ░Ź ņŗ£ņ▓Ł ĒÖ£ņä▒ĒÖö Ļ┤Ćļ”¼ ĒĢ┤ļō£ļ”Įļŗłļŗż.',
      discountRate: 16,
      originalPrice: 6000,
      price: 5000,
      category: 'ņ£ĀĒŖ£ļĖī',
      image: 'youtube.png',
      background: '/images/card-bg1.png',
      clickCount: 1800,
      rating: 4.7,
      reviewCount: 2671,
    },
    {
      id: 2,
      name: 'ĒÄśņØ┤ņŖżļČü ĒīöļĪ£ņøī 1000ļ¬ģ',
      description: 'ņ¦äņ¦£ ĒīöļĪ£ņøīļĪ£ ĒÄśņØ┤ņ¦Ć ņŗĀļó░ļÅä ņāüņŖ╣!',
      discountRate: 10,
      originalPrice: 55000,
      price: 50000,
      category: 'ĒÄśņØ┤ņŖżļČü',
      image: 'facebook.png',
      background: '/images/card-bg2.png',
      clickCount: 1200,
      rating: 4.5,
      reviewCount: 1200,
    },
    {
      id: 3,
      name: 'ĒÄśņØ┤ņŖżļČü ņóŗņĢäņÜö 2000Ļ░£',
      description: 'ĒÄśņØ┤ņ¦Ć/Ļ▓īņŗ£ļ¼╝ ņóŗņĢäņÜö ļ╣ĀļźĖ ņ”ØĻ░Ć!',
      discountRate: 20,
      originalPrice: 50000,
      price: 40000,
      category: 'ĒÄśņØ┤ņŖżļČü',
      image: 'facebook.png',
      background: '/images/card-bg3.png',
      clickCount: 1100,
      rating: 4.3,
      reviewCount: 800,
    },
    {
      id: 4,
      name: 'ņØĖņŖżĒāĆĻĘĖļ×© ĒīöļĪ£ņøī 500ļ¬ģ',
      description: 'ņŗżņĀ£ ņ£ĀņĀĆ ĻĖ░ļ░ś ĒīöļĪ£ņøī ņ”ØĻ░Ć!',
      discountRate: 25,
      originalPrice: 40000,
      price: 30000,
      category: 'ņØĖņŖżĒāĆĻĘĖļ×©',
      image: 'instagram.png',
      background: '/images/card-bg4.png',
      clickCount: 950,
      rating: 4.8,
      reviewCount: 1500,
    },
    { id: 5, name: 'ĒŖĖņ£äĒä░ ĒīöļĪ£ņøī 300ļ¬ģ', price: '20,000ņøÉ', category: 'ĒŖĖņ£äĒä░', image: 'twitter.png', background: '', clickCount: 600 },
    { id: 6, name: 'ĒģöļĀłĻĘĖļ×© ļ®żļ▓ä 200ļ¬ģ', price: '15,000ņøÉ', category: 'ĒģöļĀłĻĘĖļ×©', image: 'telegram.png', background: '', clickCount: 400 },
    { id: 7, name: 'ņ£ĀĒŖ£ļĖī ņĪ░ĒÜīņłś 10000ĒÜī', price: '60,000ņøÉ', category: 'ņ£ĀĒŖ£ļĖī', image: 'youtube.png', background: '', clickCount: 1600 },
    { id: 8, name: 'ļĖöļĪ£ĻĘĖ ļīōĻĖĆ 100Ļ░£', price: '35,000ņøÉ', category: 'ļĖöļĪ£ĻĘĖ', image: 'blog.png', background: '', clickCount: 500 },
    { id: 9, name: 'ĒŖĖņ£äĒä░ ļ”¼ĒŖĖņ£Ś 500Ļ░£', price: '45,000ņøÉ', category: 'ĒŖĖņ£äĒä░', image: 'twitter.png', background: '', clickCount: 300 },
    { id: 10, name: 'ĒģöļĀłĻĘĖļ×© ļĘ░ 1000ĒÜī', price: '30,000ņøÉ', category: 'ĒģöļĀłĻĘĖļ×©', image: 'telegram.png', background: '', clickCount: 200 },
  ];

  // Ēü┤ļ”Łņłś ļé┤ļ”╝ņ░©ņł£ ņĀĢļĀ¼ Ēøä ņāüņ£ä 10Ļ░£ļ¦ī ņé¼ņÜ®
  const topProducts = [...popularProducts].sort((a, b) => (b.clickCount ?? 0) - (a.clickCount ?? 0)).slice(0, 10);

  const filteredProducts: Product[] = selectedCategory === 'ņĀäņ▓┤' 
    ? popularProducts 
    : popularProducts.filter(product => product.category === selectedCategory);

  // ņŖ¼ļØ╝ņØ┤ļō£ Ļ┤ĆļĀ©
  useLayoutEffect(() => {
    if (trackRef.current) {
      setContainerWidth(trackRef.current.offsetWidth);
    }
    const handleResize = () => {
      if (trackRef.current) setContainerWidth(trackRef.current.offsetWidth);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [slidesToShow]);

  const maxIndex = Math.max(0, topProducts.length - slidesToShow);
  const handlePrev = () => setSlideIndex(idx => Math.max(0, idx - 1));
  const handleNext = () => setSlideIndex(idx => Math.min(maxIndex, idx + 1));

  const toggleFavorite = (id: number) => {
    setFavorites((prev) =>
      prev.includes(id) ? prev.filter((fid) => fid !== id) : [...prev, id]
    );
  };

  const gapPx = 16; // gap-x-4
  const totalGap = gapPx * (slidesToShow - 1);
  const cardWidthPx = slidesToShow > 0 ? (containerWidth - totalGap) / slidesToShow : 0;
  const moveX = slideIndex * (cardWidthPx + gapPx);

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hero Section */}
      <div className="bg-gradient-to-r from-blue-600 to-blue-800 text-white py-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h1 className="text-4xl md:text-6xl font-bold mb-6">
            ņåīņģ£ļ»Ėļööņ¢┤ ļ¦łņ╝ĆĒīģņØś ņāłļĪ£ņÜ┤ ĻĖ░ņżĆ
          </h1>
          <p className="text-xl md:text-2xl mb-8 text-blue-100">
            ņĢĀļō£ļ¬©ņ¢┤ņÖĆ ĒĢ©Ļ╗ś ļŗ╣ņŗĀņØś ņåīņģ£ļ»Ėļööņ¢┤ļź╝ ņä▒ņ×źņŗ£ĒéżņäĖņÜö
          </p>
          <Link
            to="/products"
            className="bg-white text-blue-600 px-8 py-3 rounded-lg text-lg font-semibold hover:bg-gray-100 transition duration-300"
          >
            ņāüĒÆł ļ│┤ĻĖ░
          </Link>
        </div>
      </div>

      {/* Popular Products Section - ņŖ¼ļØ╝ņØ┤ļō£ */}
      <div className="max-w-7xl mx-auto px-4 py-12">
        <h2 className="text-2xl font-bold text-gray-900 mb-6 pt-4">ņØĖĻĖ░ ņāüĒÆł</h2>
        <div className="relative">
          <button
            className="absolute -left-4 top-1/2 -translate-y-1/2 z-10 bg-white/10 border rounded-full w-12 h-12 flex items-center justify-center shadow hover:bg-gray-100"
            onClick={handlePrev}
            disabled={slideIndex === 0}
            aria-label="ņØ┤ņĀä"
          >
            <FontAwesomeIcon icon={faChevronLeft} className="text-2xl text-gray-500" />
          </button>
          <div className="overflow-hidden pb-4">
            <div
              ref={trackRef}
              className="flex transition-transform duration-500 gap-x-4"
              style={{ transform: `translateX(-${moveX}px)` }}
            >
              {topProducts.map((product, idx) => (
                <Link
                  to={`/products/${product.id}`}
                  key={product.id}
                  className="relative bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition duration-300 flex-1 cursor-pointer group"
                  style={{ minWidth: cardWidthPx ? `${cardWidthPx}px` : undefined, maxWidth: cardWidthPx ? `${cardWidthPx}px` : undefined }}
                >
                  {/* ņ”ÉĻ▓©ņ░ŠĻĖ░ ļ▓äĒŖ╝ */}
                  <button
                    className="absolute top-4 right-4 z-10"
                    onClick={e => { e.preventDefault(); toggleFavorite(product.id); }}
                  >
                    <FontAwesomeIcon
                      icon={favorites.includes(product.id) ? faSolidHeart : faRegularHeart}
                      className={`text-2xl ${favorites.includes(product.id) ? 'text-red-500' : 'text-gray-300'}`}
                    />
                  </button>
                  {/* ņ╣┤ļō£ ņāüĒÆł ņØ┤ļ»Ėņ¦Ć */}
                  <div
                    className="flex justify-center items-center h-40 p-6 bg-cover bg-center transition-transform duration-300 group-hover:scale-110"
                    style={{
                      backgroundImage: product.background ? `url(${product.background})` : undefined,
                      backgroundColor: !product.background ? '#FFF7ED' : undefined
                    }}
                  >
                    <FontAwesomeIcon
                      icon={categoryIcon[product.category]?.icon}
                      className={`text-5xl ${categoryIcon[product.category]?.color}`}
                    />
                  </div>
                  {/* ņ╣┤ļō£ ļé┤ņÜ® */}
                  <div className="p-4">
                    <h3 className="font-semibold text-gray-900 mb-1">{product.name}</h3>
                    <p className="text-gray-500 text-sm mb-2 truncate">{product.description}</p>
                    <div className="flex items-end mb-2">
                      {product.discountRate && (
                        <span className="text-blue-600 font-bold text-lg mr-2">{product.discountRate}%</span>
                      )}
                      {product.originalPrice && (
                        <span className="text-gray-400 line-through text-sm mr-2">{product.originalPrice.toLocaleString()}ņøÉ</span>
                      )}
                      <span className="text-gray-900 font-bold text-lg">{typeof product.price === 'number' ? product.price.toLocaleString() : product.price}ņøÉ</span>
                    </div>
                    <div className="flex items-center">
                      {/* ļ│äņĀÉ Ēæ£ņŗ£ */}
                      {(() => {
                        const stars = [];
                        const rating = product.rating ?? 0;
                        for (let i = 1; i <= 5; i++) {
                          if (rating >= i) {
                            stars.push(<FontAwesomeIcon key={i} icon={faSolidStar} className="text-yellow-400" />);
                          } else if (rating >= i - 0.5) {
                            stars.push(<FontAwesomeIcon key={i} icon={faStarHalfAlt} className="text-yellow-400" />);
                          } else {
                            stars.push(<FontAwesomeIcon key={i} icon={faRegularStar} className="text-gray-300" />);
                          }
                        }
                        return stars;
                      })()}
                      <span className="text-gray-700 font-medium ml-2 mr-1">{product.rating?.toFixed(1)}</span>
                      <span className="text-gray-400 text-xs">({product.reviewCount?.toLocaleString()})</span>
                    </div>
                  </div>
                </Link>
              ))}
            </div>
          </div>
          <button
            className="absolute -right-4 top-1/2 -translate-y-1/2 z-10 bg-white/10 border rounded-full w-12 h-12 flex items-center justify-center shadow hover:bg-gray-100"
            onClick={handleNext}
            disabled={slideIndex === maxIndex}
            aria-label="ļŗżņØī"
          >
            <FontAwesomeIcon icon={faChevronRight} className="text-2xl text-gray-500" />
          </button>
        </div>
      </div>

      {/* Category Filter */}
      <div className="max-w-7xl mx-auto px-4 py-8">
        <div className="flex flex-wrap gap-4 border border-gray-200 rounded-full p-8">
          {categories.map((category) => (
            <button
              key={category}
              onClick={() => setSelectedCategory(category)}
              className={`px-4 py-2 rounded-full text-[18px] font-medium transition duration-300 ${
                selectedCategory === category
                  ? 'bg-blue-600 text-white'
                  : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
              }`}
            >
              {category}
            </button>
          ))}
        </div>
      </div>

      {/* All Products Section */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <h2 className="text-2xl font-bold text-gray-900 mb-8">ņĀäņ▓┤ ņāüĒÆł</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          {filteredProducts.map((product) => (
            <Link
              to={`/products/${product.id}`}
              key={product.id}
              className="block bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition duration-300 cursor-pointer relative"
            >
              <button
                className="absolute top-4 right-4 z-10"
                onClick={e => { e.preventDefault(); toggleFavorite(product.id); }}
              >
                <FontAwesomeIcon
                  icon={favorites.includes(product.id) ? faSolidHeart : faRegularHeart}
                  className={`text-2xl ${favorites.includes(product.id) ? 'text-red-500' : 'text-gray-300'}`}
                />
              </button>
              <div className="flex justify-center items-center h-40 bg-orange-50 p-6">
                <FontAwesomeIcon
                  icon={categoryIcon[product.category]?.icon}
                  className={`text-5xl ${categoryIcon[product.category]?.color}`}
                />
              </div>
              <div className="p-4">
                <h3 className="font-semibold text-gray-900 mb-1">{product.name}</h3>
                <p className="text-gray-500 text-sm mb-2 truncate">{product.description}</p>
                <div className="flex items-end mb-2">
                  {product.discountRate && (
                    <span className="text-blue-600 font-bold text-lg mr-2">{product.discountRate}%</span>
                  )}
                  {product.originalPrice && (
                    <span className="text-gray-400 line-through text-sm mr-2">{product.originalPrice.toLocaleString()}ņøÉ</span>
                  )}
                  <span className="text-gray-900 font-bold text-lg">{typeof product.price === 'number' ? product.price.toLocaleString() : product.price}ņøÉ</span>
                </div>
                <div className="flex items-center">
                  {/* ļ│äņĀÉ Ēæ£ņŗ£ */}
                  {(() => {
                    const stars = [];
                    const rating = product.rating ?? 0;
                    for (let i = 1; i <= 5; i++) {
                      if (rating >= i) {
                        stars.push(<FontAwesomeIcon key={i} icon={faSolidStar} className="text-yellow-400" />);
                      } else if (rating >= i - 0.5) {
                        stars.push(<FontAwesomeIcon key={i} icon={faStarHalfAlt} className="text-yellow-400" />);
                      } else {
                        stars.push(<FontAwesomeIcon key={i} icon={faRegularStar} className="text-gray-300" />);
                      }
                    }
                    return stars;
                  })()}
                  <span className="text-gray-700 font-medium ml-2 mr-1">{product.rating?.toFixed(1)}</span>
                  <span className="text-gray-400 text-xs">({product.reviewCount?.toLocaleString()})</span>
                </div>
              </div>
            </Link>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Home;
